INSERT INTO disney_castle_rooms (castle_id, room_name, order_index, panorama_url, audio_guide_text) VALUES
('412e3a5a-2a6d-42d6-8ba1-5308b3c531a1', 'Royal Rose Garden', 11, '/placeholder.svg', 'Stroll through the magnificent rose garden with thousands of blooming flowers.'),
('412e3a5a-2a6d-42d6-8ba1-5308b3c531a1', 'Enchanted Fountain Plaza', 12, '/placeholder.svg', 'Watch the magical fountains dance to Disney music in this beautiful plaza.'),
('412e3a5a-2a6d-42d6-8ba1-5308b3c531a1', 'Castle Moat Bridge', 13, '/placeholder.svg', 'Cross the iconic bridge over the sparkling moat surrounding the castle.'),
('412e3a5a-2a6d-42d6-8ba1-5308b3c531a1', 'Royal Pavilion Gardens', 14, '/placeholder.svg', 'Explore the peaceful pavilion gardens with exotic plants and butterflies.'),
('412e3a5a-2a6d-42d6-8ba1-5308b3c531a1', 'Main Street View', 15, '/placeholder.svg', 'The grand finale - see the castle from Main Street USA perspective.');
INSERT INTO disney_castle_rooms (castle_id, room_name, order_index, panorama_url, audio_guide_text) VALUES
('576c1dcc-1894-41a8-9686-ddb4546738aa', 'Wishing Well Garden', 11, '/placeholder.svg', 'Make a wish at the famous wishing well surrounded by beautiful gardens.'),
