INSERT INTO disney_castle_rooms (castle_id, room_name, order_index, panorama_url, audio_guide_text) VALUES
('f67e89fa-2a35-4ed2-a598-d8378d3899e6', 'Tangled Tower Garden', 11, '/placeholder.svg', 'Rapunzels tower surrounded by purple flowers and lanterns.'),
